"""matplotlib._docstring — docstring interpolation."""

class Substitution:
    def __init__(self, *args, **kwargs):
        if args and hasattr(args[0], 'items'):
            self.params = args[0]
        else:
            self.params = kwargs
    def __call__(self, func):
        return func
    def update(self, *args, **kwargs):
        self.params.update(*args, **kwargs)

def copy(source):
    def decorator(func):
        return func
    return decorator

def dedent_interpd(func):
    return func

def interpd(func):
    return func
